// app.js - Secure version with error handling & validation
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const morgan = require('morgan');
const validator = require('validator');
const dotenv = require('dotenv');

// Load environment variables
dotenv.config();

const app = express();
const PORT = process.env.PORT || 3000;
const NODE_ENV = process.env.NODE_ENV || 'development';

// Security Middleware - Helmet
app.use(helmet());

// Logging Middleware
app.use(morgan(NODE_ENV === 'production' ? 'combined' : 'dev'));

// Body Parser Middleware
app.use(express.json({ limit: '10kb' })); // Limit payload size
app.use(express.urlencoded({ limit: '10kb', extended: true }));

// Rate Limiting Middleware
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP',
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// Error handling wrapper
const asyncHandler = (fn) => (req, res, next) => {
  Promise.resolve(fn(req, res, next)).catch(next);
};

// Health Check Endpoint
app.get('/health', asyncHandler(async (req, res) => {
  // Validate timestamp generation (safety check)
  const timestamp = new Date().toISOString();

  if (!timestamp) {
    throw new Error('Failed to generate timestamp');
  }

  res.json({ 
    status: 'ok', 
    timestamp,
    environment: NODE_ENV
  });
}));

// Users Endpoint with Input Validation
app.get('/users', asyncHandler(async (req, res) => {
  // Validate query parameters
  const { limit = 10, offset = 0, sortBy = 'id' } = req.query;

  // Input validation
  const validationErrors = [];

  if (!Number.isInteger(Number(limit)) || limit < 1 || limit > 100) {
    validationErrors.push('limit must be an integer between 1 and 100');
  }

  if (!Number.isInteger(Number(offset)) || offset < 0) {
    validationErrors.push('offset must be a non-negative integer');
  }

  const allowedSortFields = ['id', 'name', 'email'];
  if (!allowedSortFields.includes(sortBy)) {
    validationErrors.push(`sortBy must be one of: ${allowedSortFields.join(', ')}`);
  }

  if (validationErrors.length > 0) {
    return res.status(400).json({
      error: 'Invalid input',
      details: validationErrors
    });
  }

  try {
    // Mock data - in production, query database
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Apply sorting
    const sortFactor = sortBy === 'name' || sortBy === 'email' ? 1 : 0;
    if (sortFactor) {
      users.sort((a, b) => a[sortBy].localeCompare(b[sortBy]));
    }

    // Apply pagination
    const paginatedUsers = users.slice(Number(offset), Number(offset) + Number(limit));

    res.json({
      data: paginatedUsers,
      pagination: {
        limit: Number(limit),
        offset: Number(offset),
        total: users.length
      }
    });
  } catch (error) {
    throw new Error(`Failed to retrieve users: ${error.message}`);
  }
}));

// 404 Handler
app.use((req, res) => {
  res.status(404).json({
    error: 'Not Found',
    path: req.path
  });
});

// Global Error Handler
app.use((err, req, res, next) => {
  console.error('Error:', {
    message: err.message,
    stack: NODE_ENV === 'development' ? err.stack : undefined,
    path: req.path,
    method: req.method
  });

  // Don't leak error details in production
  const statusCode = err.statusCode || 500;
  const message = NODE_ENV === 'production' 
    ? 'Internal Server Error' 
    : err.message;

  res.status(statusCode).json({
    error: message,
    ...(NODE_ENV === 'development' && { stack: err.stack })
  });
});

// Server startup with error handling
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT} in ${NODE_ENV} mode`);
});

// Handle unhandled rejections
process.on('unhandledRejection', (err) => {
  console.error('Unhandled Rejection:', err);
  process.exit(1);
});

module.exports = app;
```

