        }
      });
    } catch (error) {
      logger.error('Users endpoint error', {
        error: error.message,
        userId: req.user?.id,
        stack: config.nodeEnv === 'development' ? error.stack : undefined
      });
      res.status(500).json({
        error: 'Internal server error',
        message: config.nodeEnv === 'development'
          ? error.message
          : 'An error occurred processing your request'
      });
    }
  }
);

/**
 * GET /users/:id
 * Get specific user by ID (requires authentication)
 *
 * Security features:
 * - Authentication required
 * - Path parameter validation
 * - Sensitive data filtering
 */
app.get(
  '/users/:id',
  authenticateUser,
  query('include').optional().isIn(['profile', 'activity']),
  validateRequest,
  (req, res) => {
    try {
      const { id } = req.params;

      // Validate user ID is numeric
      if (!Number.isInteger(parseInt(id, 10))) {
        return res.status(400).json({
          error: 'Invalid request',
          message: 'User ID must be a number'
        });
      }

      // Check authorization (users can only view their own data unless admin)
      if (req.user.role !== 'admin' && parseInt(id, 10) !== req.user.id) {
        logger.warn('Unauthorized user access attempt', {
          requestingUserId: req.user.id,
          targetUserId: id,
          ip: req.ip
        });
        return res.status(403).json({
          error: 'Forbidden',
          message: 'You do not have permission to view this user'
        });
      }

      // Simulated user lookup
      const user = {
        id: parseInt(id, 10),
        name: 'Alice',
        email: 'alice@example.com',
        role: 'admin'
      };

      logger.info('User details accessed', {
        requestingUserId: req.user.id,
        targetUserId: id
      });

      // Filter sensitive data
      const response = {
        id: user.id,
        name: user.name
      };

      if (req.user.role === 'admin' || req.user.id === user.id) {
        response.email = user.email;
      }

      if (req.user.role === 'admin') {
        response.role = user.role;
      }

      res.status(200).json(response);
    } catch (error) {
      logger.error('User detail endpoint error', {
        error: error.message,
        userId: req.user?.id,
        stack: config.nodeEnv === 'development' ? error.stack : undefined
      });
      res.status(500).json({
        error: 'Internal server error'
      });
    }
  }
);

// ============================================================================
// ERROR HANDLING MIDDLEWARE
// ============================================================================

/**
 * 404 Not Found handler
 */
app.use((req, res) => {
  logger.warn('404 Not Found', {
    method: req.method,
    path: req.path,
    ip: req.ip
  });
  res.status(404).json({
    error: 'Not Found',
    message: `${req.method} ${req.path} not found`,
    path: req.path
  });
});

/**
 * Global error handler
 * Must be defined last
 */
app.use((err, req, res, next) => {
  const status = err.status || err.statusCode || 500;
  const message = err.message || 'Internal Server Error';

  // Log error with full context
  logger.error('Unhandled error', {
    status,
    message,
    path: req.path,
    method: req.method,
    ip: req.ip,
    userId: req.user?.id,
    stack: config.nodeEnv === 'development' ? err.stack : undefined
  });

  // Send response (don't leak stack traces in production)
  const response = {
    error: message,
    ...(config.nodeEnv === 'development' && { stack: err.stack })
  };

  res.status(status).json(response);
});

// ============================================================================
// SERVER STARTUP
// ============================================================================

const server = app.listen(config.port, config.host, () => {
  logger.info('Server started', {
    port: config.port,
    host: config.host,
    environment: config.nodeEnv
  });
});

// Graceful shutdown
process.on('SIGTERM', () => {
  logger.info('SIGTERM signal received: closing HTTP server');
  server.close(() => {
    logger.info('HTTP server closed');
    process.exit(0);
  });
});

process.on('SIGINT', () => {
  logger.info('SIGINT signal received: closing HTTP server');
  server.close(() => {
    logger.info('HTTP server closed');
    process.exit(0);
  });
});

// Unhandled rejection handler
process.on('unhandledRejection', (reason, promise) => {
  logger.error('Unhandled Rejection', {
    reason,
    promise: promise.toString()
  });
  process.exit(1);
});

module.exports = app;
